// Store important data for later use
const apifyResponse = $input.first().json;
const originalRow = $('Process One Row at a Time').item.json;

return [{
  json: {
    apifyRunId: apifyResponse.data.id,
    apifyActId: apifyResponse.data.actId,
    rowNumber: originalRow.row_number,
    linkedInUrl: originalRow['LinkedIn'],
    loopCount: 0
  }
}];

// Preserve original data and update status
const statusResponse = $input.first().json;
const previousData = $('Wait 15 Seconds').item.json;

return [{
  json: {
    apifyRunId: previousData.apifyRunId,
    apifyActId: previousData.apifyActId,
    rowNumber: previousData.rowNumber,
    linkedInUrl: previousData.linkedInUrl,
    loopCount: previousData.loopCount + 1,
    status: statusResponse.data.status
  }
}];

// Prepare error message
const runInfo = $input.first().json;

return [{
  json: {
    rowNumber: runInfo.rowNumber,
    linkedInData: `Error: Failed after ${runInfo.loopCount} attempts`
  }
}];

// Get the experiences array safely
const experiences = Array.isArray($json.experiences) ? $json.experiences : [];

// Helper: clean strings (prevents random \n, \r issues)
const clean = (v) => String(v ?? '').replace(/[\r\n]+/g, ' ').trim();

// Helper: treat blanks/nulls as N/A
const valOrNA = (v) => {
  const s = clean(v);
  return s ? s : 'N/A';
};

// Current date in MM-YYYY (force Asia/Tokyo)
const currentMMYYYY = (() => {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Asia/Tokyo',
    year: 'numeric',
    month: '2-digit',
  }).formatToParts(new Date());

  const year = parts.find((p) => p.type === 'year')?.value || String(new Date().getFullYear());
  const month =
    parts.find((p) => p.type === 'month')?.value || String(new Date().getMonth() + 1).padStart(2, '0');

  return `${month}-${year}`;
})();

// Helper: determine if a role is current
const isCurrentRole = (exp) => {
  if (!exp || typeof exp !== 'object') return false;

  // Prefer explicit boolean when present
  if (typeof exp.jobStillWorking === 'boolean') return exp.jobStillWorking;

  // Fallback: infer from missing/empty end date
  const ended = exp.jobEndedOn;
  return ended === null || ended === undefined || String(ended).trim() === '';
};

// All current roles (in the original order)
const currentRoles = experiences.filter(isCurrentRole);

// Treat the first current role as the "primary" one, others are "additional"
const additionalCurrentRoles = currentRoles.slice(1);

// Format additional current roles (include industry + size if present)
const formattedJobs = additionalCurrentRoles
  .map((exp, i) => {
    const title = valOrNA(exp.title);
    const company = valOrNA(exp.companyName);
    const started = valOrNA(exp.jobStartedOn);
    const employmentType = valOrNA(exp.employmentType);
    const companyIndustry = valOrNA(exp.companyIndustry);
    const companySize = valOrNA(exp.companySize);

    // Prefer explicit jobLocation; fall back to jobLocationCountry if present
    const location = clean(exp.jobLocation) || clean(exp.jobLocationCountry) || 'N/A';

    const desc = clean(exp.jobDescription) ? clean(exp.jobDescription) : 'No description';

    return [
      `additional_current_role_${i + 1}:`,
      `- job_title: ${title}`,
      `- job_description: ${desc}`,
      `- company: ${company}`,
      `- company_industry: ${companyIndustry}`,
      `- company_size: ${companySize}`,
      `- employment_type: ${employmentType}`,
      `- location: ${location}`,
      `- started: ${started} (current as of ${currentMMYYYY})`,
    ].join('\n');
  })
  .join('\n\n');

return [
  {
    json: {
      additionalCurrentJobs: formattedJobs || 'No additional current jobs',
      count: additionalCurrentRoles.length,
      currentRolesCount: currentRoles.length,
    },
  },
];

