  (() => {
    const exps = Array.isArray($json.experiences) ? $json.experiences : [];
    if (!exps.length) return '';

    const clean = (v) => String(v ?? '').replace(/[\r\n]+/g, '').trim();

    const isCurrent = (exp) => {
      if (!exp) return false;
      if (typeof exp.jobStillWorking === 'boolean') return exp.jobStillWorking;
      const ended = exp.jobEndedOn;
      return ended === null || ended === undefined || String(ended).trim() === '';
    };

    // Find the first current role (the "main" current role)
    const currentIdx = exps.findIndex(isCurrent);

    // Previous role = the first non-current role after the current one
    const prev = exps.slice(Math.max(currentIdx + 1, 0)).find(exp => exp && !isCurrent(exp));

    // If we can't find a previous role, fall back to experiences[1] if present
    const target = prev || exps[1];
    if (!target) return '';

    const name = clean(target.companyName) || 'N/A';
    const endedStr = clean(target.jobEndedOn);

    return endedStr
      ? `${name} - ended on ${endedStr}`
      : `${name} - but no end date listed`;
  })()
}}

